"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "High BMI And Follow Up Provided" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Low BMI And Follow Up Provided" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Normal BMI" AS sub WHERE sub.patient_id = p.patient_id)
),
"Qualifying Encounter During Day Of Measurement Period" AS (
SELECT * FROM "Encounter: Encounter to Evaluate BMI" AS BMIEncounter WHERE CAST(intervalStart(fhirpath_text(BMIEncounter.resource, 'period')) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(BMIEncounter.resource, 'period')) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND NOT fhirpath_bool(BMIEncounter.resource, 'class.where(system=''http://terminology.hl7.org/CodeSystem/v3-ActCode'' and code=''VR'').exists()') AND BMIEncounter.status = 'finished'
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Qualifying Encounter During Day Of Measurement Period" AS QualifyingEncounter WHERE QualifyingEncounter.patient_id = p.patient_id AND EXTRACT(YEAR FROM CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = QualifyingEncounter.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = QualifyingEncounter.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = QualifyingEncounter.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = QualifyingEncounter.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 18)
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Is Pregnant During Day Of Measurement Period" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Pregnancy or Other Related Diagnoses (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Pregnancy or Other Related Diagnoses (qicore-condition-encounter-diagnosis)") AS PregnancyDiagnosis WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying Encounter During Day Of Measurement Period") AS QualifyingEncounter WHERE fhirpath_bool(PregnancyDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') AND CAST(intervalStart(CASE WHEN fhirpath_text(PregnancyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), fhirpath_text(PregnancyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(PregnancyDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(PregnancyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), fhirpath_text(PregnancyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(PregnancyDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND QualifyingEncounter.patient_id = PregnancyDiagnosis.patient_id)
),
