),
"Medical Reason For Not Documenting A Follow Up Plan For Low Or High BMI" AS (
(SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: Referrals Where Weight Assessment May Occur (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Follow Up for Above Normal BMI (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Follow Up for Below Normal BMI (servicenotrequested)") AS NoBMIFollowUp WHERE CASE WHEN fhirpath_text(NoBMIFollowUp.resource, 'status') IS NULL AND 'completed' IS NULL THEN TRUE WHEN fhirpath_text(NoBMIFollowUp.resource, 'status') IS NULL OR 'completed' IS NULL THEN FALSE ELSE fhirpath_text(NoBMIFollowUp.resource, 'status') = 'completed' END AND in_valueset(NoBMIFollowUp.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-doNotPerformReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1007') AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying Encounter During Day Of Measurement Period") AS QualifyingEncounter WHERE CAST(fhirpath_text(NoBMIFollowUp.resource, 'authoredOn') AS DATE) = CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) AND QualifyingEncounter.patient_id = NoBMIFollowUp.patient_id)) UNION (SELECT * FROM (SELECT patient_id, resource FROM "MedicationRequest: Medications for Above Normal BMI (medicationnotrequested)" UNION SELECT patient_id, resource FROM "MedicationRequest: Medications for Below Normal BMI (medicationnotrequested)") AS NoBMIFollowUp WHERE CASE WHEN fhirpath_text(NoBMIFollowUp.resource, 'status') IS NULL AND 'completed' IS NULL THEN TRUE WHEN fhirpath_text(NoBMIFollowUp.resource, 'status') IS NULL OR 'completed' IS NULL THEN FALSE ELSE fhirpath_text(NoBMIFollowUp.resource, 'status') = 'completed' END AND in_valueset(NoBMIFollowUp.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1007') AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying Encounter During Day Of Measurement Period") AS QualifyingEncounter WHERE CAST(fhirpath_text(NoBMIFollowUp.resource, 'authoredOn') AS DATE) = CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) AND QualifyingEncounter.patient_id = NoBMIFollowUp.patient_id))
),
"Medical Reason Or Patient Reason For Not Performing BMI Exam" AS (
SELECT * FROM "Observation: Body mass index (BMI) [Ratio] (observationcancelled)" AS NoBMI WHERE NoBMI.status = 'cancelled' AND (in_valueset(NoBMI.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-notDoneReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1582') OR in_valueset(NoBMI.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-notDoneReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1007')) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying Encounter During Day Of Measurement Period") AS QualifyingEncounter WHERE CAST(intervalEnd(CASE WHEN fhirpath_text(NoBMI.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(NoBMI.resource, 'effective')), '{') THEN fhirpath_text(NoBMI.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(NoBMI.resource, 'effective'), fhirpath_text(NoBMI.resource, 'effective'), TRUE, TRUE) END) AS DATE) = CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) AND QualifyingEncounter.patient_id = NoBMI.patient_id)
),
"Denominator Exceptions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Medical Reason For Not Documenting A Follow Up Plan For Low Or High BMI" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Medical Reason Or Patient Reason For Not Performing BMI Exam" AS sub WHERE sub.patient_id = p.patient_id)
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Denominator Exceptions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exceptions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Denominator Exceptions" ON p.patient_id = "Denominator Exceptions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
